import React from "react";

import styles from "./LoadingOverlayCrystalline.module.css";

export interface LoadingOverlayCrystallineProps {
  message: string;
  subtext?: string;
  icon?: React.ReactNode;
  showEffect?: boolean;
}

export function LoadingOverlayCrystalline({
  message,
  subtext,
  icon,
  showEffect = false,
}: LoadingOverlayCrystallineProps) {
  return (
    <div className={`${styles.root} ${showEffect ? "" : styles.noEffect}`.trim()}>
      <div className={styles.card}>
        {icon ? <span className={styles.icon}>{icon}</span> : null}
        <div>
          <div>{message}</div>
          {subtext ? <div className={styles.subtext}>{subtext}</div> : null}
        </div>
      </div>
    </div>
  );
}

export default LoadingOverlayCrystalline;

.root {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: var(--z-viewer-quick-tools);
  background: transparent;
}

.noEffect {
  background: transparent;
}

.card {
  position: relative;
  z-index: 20;
  display: inline-flex;
  align-items: center;
  gap: 10px;
  padding: 14px 16px;
  background: color-mix(in srgb, var(--bg-primary) 85%, transparent);
  border: 1px solid color-mix(in srgb, var(--text-primary) 14%, transparent);
  border-radius: 10px;
  color: var(--text-primary);
  font-size: 14px;
  font-weight: 600;
}

.icon {
  opacity: 0.9;
}

.subtext {
  margin-top: 2px;
  color: color-mix(in srgb, var(--text-secondary) 92%, transparent);
  font-size: 12px;
  font-weight: 500;
}
